import { defineConfig } from 'astro/config'
import starlight from '@astrojs/starlight'

export default defineConfig({
  site: 'https://fastlabai.github.io',
  base: '/design-editor',

  vite: {
    build: {
      commonjsOptions: {
        // postcss (bundled into Astro's SSR/prerender chunk) does
        //   let { nanoid } = require('nanoid/non-secure')
        // nanoid v3/v5 ship ESM with named exports only (no `default`), so
        // the default-interop generated by @rollup/plugin-commonjs throws
        // "does not provide an export named 'default'" at prerender time.
        // Forcing namespace interop for nanoid emits `import * as ns` and
        // destructures named exports directly.
        requireReturnsDefault: (id) =>
          id.includes('nanoid/non-secure') ? 'namespace' : false,
      },
    },
  },

  integrations: [
    starlight({
      title: '@fastlab-ai/design-editor',
      social: [
        { icon: 'github', label: 'GitHub', href: 'https://github.com/fastlabai/design-editor' },
      ],
      sidebar: [
        { label: 'Getting Started', link: '/getting-started' },
        { label: 'Next.js', link: '/nextjs' },
        {
          label: 'Providers',
          items: [
            { label: 'Media', link: '/providers/media' },
            { label: 'Fonts', link: '/providers/fonts' },
            { label: 'Background Removal', link: '/providers/background-removal' },
            { label: 'Persistence', link: '/providers/persistence' },
          ],
        },
        { label: 'API Reference', link: '/api' },
      ],
    }),
  ],
})
